"use client";

import type { CSSProperties } from "react";
import { getLegacyBaseUrl } from "../../lib/api";

const containerStyle: CSSProperties = {
  maxWidth: 420,
  margin: "48px auto",
  padding: 24,
  background: "rgba(255,255,255,0.06)",
  borderRadius: 12,
  border: "1px solid rgba(255,255,255,0.2)"
};

const linkStyle: CSSProperties = {
  display: "inline-block",
  marginTop: 16,
  padding: "10px 18px",
  borderRadius: "10px",
  border: "1px solid rgba(255,255,255,0.25)",
  fontWeight: 600,
  color: "#e2e8f0"
};

export default function LoginPage() {
  const legacyBase = getLegacyBaseUrl();
  return (
    <main className="container" style={{ paddingTop: 24 }}>
      <div style={containerStyle}>
        <h1 style={{ marginTop: 0 }}>Masuk (TSX)</h1>
        <p style={{ marginBottom: 16 }}>Halaman login dalam format TSX. Form lengkap di backend lama.</p>
        <a href={`${legacyBase}/login`} style={linkStyle}>Buka halaman login lengkap</a>
        <br />
        <a href="/" style={{ ...linkStyle, marginLeft: 8 }}>Kembali ke beranda</a>
      </div>
    </main>
  );
}
